export const MILITARY_CALLSIGN_PREFIXES = new Set([
  'RCH', 'RRR', 'CNV', 'FORTE', 'LAGR', 'NATO', 'QID', 'BAF', 'IAM', 'SUI', 'NVY', 'GAF', 'HAF', 'ASY', 'ROF', 'UAF', 'RFF', 'TUAF', 'ARMY', 'NAVY', 'SPAR',
  'REACH', 'PAT', 'FNY', 'KAF', 'BRS', 'MOOSE', 'DUKE', 'RFR', 'SAM', 'BOXER', 'HOMER', 'SHELL', 'JEEP', 'ORCA', 'SCOUT'
]);

export function classifyAircraft(model, category) {
  const normalizedModel = (model || '').toUpperCase();
  const normalizedCategory = (category || '').toLowerCase();

  if (normalizedCategory === 'heli' || HELI_TYPES.has(normalizedModel)) {
    return 'heli';
  }

  if (normalizedCategory === 'military') {
    return 'military';
  }

  if (BIZJET_TYPES.has(normalizedModel)) {
    return 'bizjet';
  }

  if (TURBOPROP_TYPES.has(normalizedModel)) {
    return 'turboprop';
  }

  return 'airliner';
}

export function mapClassificationToAircraftType(classification) {
  if (classification === 'heli') {
    return 'Helicopter';
  }

  if (classification === 'turboprop') {
    return 'Regional';
  }

  if (classification === 'bizjet') {
    return 'Jet';
  }

  if (classification === 'military') {
    return 'Military';
  }

  return 'Jet';
}

export function inferMilitaryByCallsign(callsign) {
  if (!callsign) {
    return false;
  }

  const normalized = callsign.replace(/[^A-Z0-9]/gi, '').toUpperCase();
  if (!normalized) {
    return false;
  }

  const alphaPrefix = normalized.replace(/[0-9].*$/, '');
  if (!alphaPrefix) {
    return false;
  }

  for (const prefix of MILITARY_CALLSIGN_PREFIXES) {
    if (alphaPrefix.startsWith(prefix)) {
      return true;
    }
  }

  return false;
}
